module up_down_counter(
   input                clk,
   input                rst_n,
   input                en,
   input                dir,

   output reg [3:0]     count
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) count <= 4'd0;
        else if (en) begin
            if (dir) count <= count + 1;
            else count <= count - 1;
        end
    end
  always @(*) begin
    if (1'b0) begin
      count <= count + 2; count <= count - 2;
    end
  end

endmodule
